SELECT COUNT(1)
  FROM TORDER_REQ_WMS_HD
 WHERE 
 	   CTKEY = #{ctkey}
   AND REQHDKEY = #{reqhdkey}

SELECT COUNT(1)
  FROM TORDER_REQ_WMS_DT
 WHERE 
 	   CTKEY = #{ctkey}
   AND REQHDKEY = #{reqhdkey} 

   AND REQDTKEY = #{reqdtkey}

mapper.insert:
INSERT INTO TORDER_REQ_WMS_HD
(
	  CTKEY
	 ,REQHDKEY
	 ,EXTERNORDERKEY
	 ,OBHDTYPE
	 ,OBREQUESTDATE
	 ,OBDATE
	 ,LOGGRPCD
	 ,DCKEY
	 ,OWKEY
	 ,ACKEY
	 ,STORE_KEY
	 ,REQREASON
	 ,SO_HDKEY
	 ,ICGRKEY
	 ,INSERTDATE
	 ,INSERTURKEY
	 ,UPDATEDATE
	 ,UPDATEURKEY
	 ,FR_CTKEY
	 ,TO_CTKEY
) VALUES (
	  #{ctkey}						
	 ,#{reqhdkey}
	 ,#{externorderkey}
	 ,#{obhdtype}
	 ,#{obrequestdate}
	 ,#{obdate}
	 ,#{loggrpcd}
	 ,#{dckey}
	 ,#{owkey}
	 ,#{ackey}
	 ,#{store_key}
	 ,#{reqreason}
	 ,#{so_hdkey}
	 ,#{icgrkey}
	 ,#{sysdate}
     ,#{surkey}
	 ,#{sysdate}
     ,#{surkey}
     ,CASE #{obhdtype} WHEN '100' THEN #{fr_ctkey} ELSE '' END
	 ,CASE #{obhdtype} WHEN '110' THEN #{to_ctkey} WHEN '70' THEN #{to_ctkey} ELSE '' END
)
